public void testConvertValidASCIIIdentifiers() {
  test("a['b']", "a.b");
  test("a['$']", "a.$");
  test("a['_']", "a._");
  test("a['abc123']", "a.abc123");
  test("a['$_abc']", "a.$_abc");
}

public void testDoNotConvertNonASCIIIdentifiers() {
  testSame("a['\u00e9']");
  testSame("a['\u00f1']");
  testSame("a['\u0100']");
  testSame("a['a\u0080']");
  testSame("a['\u007fb']");
}

public void testBoundaryASCIICharacters() {
  testSame("a['\u007f']");
  test("a['z']", "a.z");
  test("a['Z']", "a.Z");
  testSame("a['{']');
}

public void testControlCharactersInMiddle() {
  testSame("a['a\u0000b']");
  testSame("a['a\u0001b']");
  testSame("a['a\u001fb']");
}
